-- Create Districts table
CREATE TABLE "Districts" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "NameAz" character varying(100) NOT NULL,
    "NameEn" character varying(100) NOT NULL,
    "NameRu" character varying(100) NOT NULL,
    "DisplayOrder" integer NOT NULL DEFAULT 0,
    "IsActive" boolean NOT NULL DEFAULT TRUE,
    "CityId" integer NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    "CreatedBy" uuid,
    "UpdatedBy" uuid,
    "IsDeleted" boolean NOT NULL DEFAULT FALSE,
    "DeletedAt" timestamp with time zone,
    "DeletedBy" uuid,
    CONSTRAINT "PK_Districts" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Districts_Cities_CityId" FOREIGN KEY ("CityId") REFERENCES "Cities" ("Id") ON DELETE RESTRICT
);

-- Add DistrictId column to PetAds
ALTER TABLE "PetAds" ADD COLUMN "DistrictId" integer;

-- Create indexes on Districts
