-- Add FK from PetAds to Districts
ALTER TABLE "PetAds" ADD CONSTRAINT "FK_PetAds_Districts_DistrictId" FOREIGN KEY ("DistrictId") REFERENCES "Districts" ("Id") ON DELETE SET NULL;

